    pub fn restore(
        &mut self,
        event_buffer: &mut EventBuffer,
        snap: &EntityTreeSnapshot,
    ) -> Result<(), RepositoryError> {
        let store_snap = snap
            .store_snapshot
            .as_ref()
            .ok_or_else(|| RepositoryError::Serialization("missing store snapshot".into()))?;
        self.transaction.restore_store(store_snap);

        let store = self.transaction.get_store();

        let mut emit = |entity: DirectAccessEntity, ids: Vec<EntityId>| {
            if !ids.is_empty() {
                event_buffer.push(Event {
                    origin: Origin::DirectAccess(entity),
                    ids,
                    data: None,
                });
            }
        };

        // Emit Created events for this entity
        let entity_ids: Vec<_> = store.entitys.read().unwrap().keys().copied().collect();
        emit(
            DirectAccessEntity::Entity(EntityEvent::Created),
            entity_ids.clone(),
        );
        emit(DirectAccessEntity::Entity(EntityEvent::Updated), entity_ids);

        // Emit Created events for strong children

        {
            let child_ids: Vec<_> = store.fields.read().unwrap().keys().copied().collect();
            emit(
                DirectAccessEntity::Field(EntityEvent::Created),
                child_ids.clone(),
            );
            emit(DirectAccessEntity::Field(EntityEvent::Updated), child_ids);
        }
        {
            let child_ids: Vec<_> = store
                .relationships
                .read()
                .unwrap()
                .keys()
                .copied()
                .collect();
            emit(
                DirectAccessEntity::Relationship(EntityEvent::Created),
                child_ids.clone(),
            );
            emit(
                DirectAccessEntity::Relationship(EntityEvent::Updated),
                child_ids,
            );
        }

        Ok(())
    }
